import{_ as r,o as s,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Sorry Cypress","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/tooling-extras/testing/frontend/sorry-cypress.md","filePath":"software-engineering/tooling-extras/testing/frontend/sorry-cypress.md"}'),a={name:"software-engineering/tooling-extras/testing/frontend/sorry-cypress.md"};function i(n,e,l,c,d,p){return s(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="sorry-cypress" tabindex="-1">Sorry Cypress <a class="header-anchor" href="#sorry-cypress" aria-label="Permalink to &quot;Sorry Cypress&quot;">​</a></h1><h2 id="dashboard-and-api" tabindex="-1">Dashboard and API <a class="header-anchor" href="#dashboard-and-api" aria-label="Permalink to &quot;Dashboard and API&quot;">​</a></h2><p>Running the full sorry-cypress kit - setting up web dashboard to store and browse test results. The <a href="https://docs.sorry-cypress.dev/guide/get-started" target="_blank" rel="noreferrer">basic</a> setup of sorry-cypress is already quite useful - we can run cypress tests in parallel without any limitations. However, we want to store and see the test results and explore errors, screenshots and videos.</p><h3 id="running-sorry-cypress-kit" tabindex="-1">Running sorry-cypress kit <a href="#persisting-test-results" id="persisting-test-results"></a> <a class="header-anchor" href="#running-sorry-cypress-kit" aria-label="Permalink to &quot;Running sorry-cypress kit &lt;a href=&quot;#persisting-test-results&quot; id=&quot;persisting-test-results&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>We are going to run the full sorry-cypress kit:</p><ol><li>1.<code>director</code> service will use MongoDB to store the test runs and the results</li><li>2.<code>API</code> service (a GraphQL interface to MongoDB) to let us issue queries and retrieve tests results</li><li>3.<code>Dashboard</code> service - a web dashboard for browsing the results</li><li>4.​<a href="https://min.io/product/overview" target="_blank" rel="noreferrer"><code>minio</code></a> will let us store files - videos and screenshots generated by cypress agent</li></ol><p>We are going to run all the services locally using <code>docker-compose</code># get docker-compose filecurl --output docker-compose.minio.yml <a href="https://raw.githubusercontent.com/sorry-cypress/sorry-cypress/master/docker-compose.minio.yml%E2%80%8B#" target="_blank" rel="noreferrer">https://raw.githubusercontent.com/sorry-cypress/sorry-cypress/master/docker-compose.minio.yml​#</a> start the servicesdocker-compose -f ./docker-compose.minio.yml up</p><ul><li>Make sure to install a modern version of <a href="https://docs.docker.com/compose/install/" target="_blank" rel="noreferrer">docker-compose</a>​</li><li>Shut down any stale sorry-cypress services with <code>docker kill</code></li></ul><p>After successfully running docker-compose, we have:</p><ul><li><code>director</code> service on <a href="http://localhost:1234/" target="_blank" rel="noreferrer">http://localhost:1234</a>​</li><li><code>API</code> service on <a href="http://localhost:4000/" target="_blank" rel="noreferrer">http://localhost:4000</a>​</li><li><code>Dashboard</code> running on <a href="http://localhost:8080/" target="_blank" rel="noreferrer">http://localhost:8080</a>​</li></ul><p>Open the dashboard at <a href="http://localhost:8080/" target="_blank" rel="noreferrer">http://localhost:8080</a>​Create a project with the id you wrote as value for <code>projectId</code> in your <code>currents.config.js</code> file (e.g., &quot;yyy&quot;).Empty sorry-cypress dashboard</p><figure><img src="https://1365695328-files.gitbook.io/~/files/v0/b/gitbook-x-prod.appspot.com/o/spaces%2F-MS6gDAYECuzpKjjzrdc%2Fuploads%2Fgit-blob-8d3ebbc022457385322ee0b33131dd8bcc3ef7ec%2Fempty-dashboard.png?alt=media" alt=""><figcaption></figcaption></figure><h4 id="setup-screenshots-upload" tabindex="-1">Setup Screenshots Upload <a href="#setup-screenshots-upload" id="setup-screenshots-upload"></a> <a class="header-anchor" href="#setup-screenshots-upload" aria-label="Permalink to &quot;Setup Screenshots Upload &lt;a href=&quot;#setup-screenshots-upload&quot; id=&quot;setup-screenshots-upload&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>We are using <code>minio</code> service to store files generated by cypress agents - video recordings and failed test screenshots. Each agent uploads the files directly to <code>minio</code>. Edit your <code>/etc/hosts</code> file to allow cypress agents to discover the local instance of <code>minio</code>127.0.0.1 storage</p><h4 id="running-cypress-tests-in-parallel" tabindex="-1">Running cypress tests in parallel. <a href="#running-cypress-tests-in-parallel" id="running-cypress-tests-in-parallel"></a> <a class="header-anchor" href="#running-cypress-tests-in-parallel" aria-label="Permalink to &quot;Running cypress tests in parallel. &lt;a href=&quot;#running-cypress-tests-in-parallel&quot; id=&quot;running-cypress-tests-in-parallel&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><code>director</code> is running in a Docker container, but it is still accessible at <a href="http://localhost:1234/" target="_blank" rel="noreferrer"><code>http://localhost:1234</code></a>. We have already reconfigured <code>cypress</code> to use this URL. Let&#39;s just rerun the tests.Open several terminal windows within a directory with tests and run <code>cypress</code> in each.# run in each terminalcypress-cloud run --parallel --record --key somekey --ci-build-id hello-cypressAs soon as agents start their execution, refresh the dashboard. You&#39;d see a new project and a new run created.Use the same <code>--ci-build-id</code> value to associate different cypress agents with the same run. Learn more about <a href="https://currents.dev/readme/guides/cypress-ci-build-id" target="_blank" rel="noreferrer">CI Build ID.</a>​</p><h4 id="exploring-the-dashboard" tabindex="-1">Exploring the dashboard <a href="#exploring-the-dashboard" id="exploring-the-dashboard"></a> <a class="header-anchor" href="#exploring-the-dashboard" aria-label="Permalink to &quot;Exploring the dashboard &lt;a href=&quot;#exploring-the-dashboard&quot; id=&quot;exploring-the-dashboard&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The dashboard is quite simple - go ahead and explore the tests you have just created. Dashboard example - list of tests and results for a runCongratulations 🎉You have set up sorry-cypress on your local machine. Now you can run unlimited cypress tests and use the dashboard to browse the results.In the next article, we&#39;ll learn how to setup sorry-cypress in the cloud using different cloud providers.</p><figure><img src="https://1365695328-files.gitbook.io/~/files/v0/b/gitbook-x-prod.appspot.com/o/spaces%2F-MS6gDAYECuzpKjjzrdc%2Fuploads%2Fgit-blob-b41a3a6ef52df8a30b25244284bd1e44366f2d3e%2Fsc-run-details.png?alt=media" alt=""><figcaption></figcaption></figure>',19)])])}const g=r(a,[["render",i]]);export{u as __pageData,g as default};
